import java.io.BufferedWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_withPath_callsFilesNewBufferedWriterAndReturnsCSVPrinter() throws IOException {
        Path mockPath = mock(Path.class);
        StringWriter stringWriter = new StringWriter();

        // Manually mock Files.newBufferedWriter(Path, Charset) using Proxy and reflection
        // because Mockito.mockStatic is not available in Mockito 3
        BufferedWriter bufferedWriter = new BufferedWriter(stringWriter);

        // Create a proxy for Files class that intercepts calls to newBufferedWriter and returns bufferedWriter
        InvocationHandler handler = (proxy, method, args) -> {
            if ("newBufferedWriter".equals(method.getName())
                    && args.length == 2
                    && args[0] == mockPath
                    && args[1] == StandardCharsets.UTF_8) {
                return bufferedWriter;
            }
            throw new UnsupportedOperationException("Method not mocked: " + method.getName());
        };

        // Because Files is final and cannot be proxied, we cannot replace it directly.
        // Instead, we will spy on csvFormat.print(Path, Charset) by overriding Files.newBufferedWriter via a subclass.

        CSVFormat csvFormatSpy = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                if (out == mockPath && charset.equals(StandardCharsets.UTF_8)) {
                    return print(bufferedWriter);
                }
                return super.print(out, charset);
            }
        };

        CSVPrinter printer = csvFormatSpy.print(mockPath, StandardCharsets.UTF_8);

        assertNotNull(printer);
    }

    @Test
    void testPrint_withPath_throwsIOException_whenFilesNewBufferedWriterThrows() throws IOException {
        Path mockPath = mock(Path.class);

        CSVFormat csvFormatSpy = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                if (out == mockPath && charset.equals(StandardCharsets.UTF_8)) {
                    throw new IOException("Test IOException");
                }
                return super.print(out, charset);
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> csvFormatSpy.print(mockPath, StandardCharsets.UTF_8));
        assertEquals("Test IOException", thrown.getMessage());
    }
}
